#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e5+5;
int n,Q,Root,a[N];
vector<int> g[N];
int Fa[N],dep[N];
int sz[N],wc[N];
int top[N],dfn[N],Cnt,fd[N];
LL MOD,sum[N*4],tag[N*4];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS1(int u,int fa){
    Fa[u]=fa,sz[u]=1;
    dep[u]=dep[fa]+1;
    for(int v:g[u])if(v^fa){
        DFS1(v,u),sz[u]+=sz[v];
        if(sz[v]>sz[wc[u]])wc[u]=v;
    }return;
}
void DFS2(int u,int Top){
    top[u]=Top;
    dfn[u]=(++Cnt),fd[Cnt]=u;
    if(wc[u])DFS2(wc[u],Top);
    for(int v:g[u])
        if(v^Fa[u]&&v^wc[u])DFS2(v,v);return;
}
int ls(int u){return (u<<1);}
int rs(int u){return (u<<1|1);}
void push_up(int u){
    sum[u]=sum[ls(u)]+sum[rs(u)];return;
}
void build(int u,int l,int r){
    if(l==r){sum[u]=a[fd[l]]%MOD,tag[u]=0;return;}
    int mid=(l+r)>>1;
    build(ls(u),l,mid),build(rs(u),mid+1,r);
    push_up(u);return;
}
void add_tag(int u,int l,int r,LL k){
    sum[u]=(sum[u]+k*(r-l+1))%MOD;
    tag[u]=(tag[u]+k)%MOD;return;
}
void push_down(int u,int l,int r){
    if(!tag[u])return;
    int mid=(l+r)>>1;
    add_tag(ls(u),l,mid,tag[u]);
    add_tag(rs(u),mid+1,r,tag[u]);
    tag[u]=0;return;
}
void change(int u,int l,int r,int L,int R,LL k){
    if(r<L||R<l)return;
    if(L<=l&&r<=R){add_tag(u,l,r,k);return;}
    int mid=(l+r)>>1;push_down(u,l,r);
    change(ls(u),l,mid,L,R,k);
    change(rs(u),mid+1,r,L,R,k);
    push_up(u);return;
}
LL ask(int u,int l,int r,int L,int R){
    if(r<L||R<l)return 0;
    if(L<=l&&r<=R)return sum[u];
    int mid=(l+r)>>1;LL res=0;
    push_down(u,l,r);
    res+=ask(ls(u),l,mid,L,R);
    res+=ask(rs(u),mid+1,r,L,R);
    return res%MOD;
}
void update(int x,int y,LL k){
    while(top[x]!=top[y]){
        if(dfn[top[x]]<dfn[top[y]])swap(x,y);
        change(1,1,n,dfn[top[x]],dfn[x],k);
        x=Fa[top[x]];
    }if(dfn[x]>dfn[y])swap(x,y);
    change(1,1,n,dfn[x],dfn[y],k);return;
}
LL query(int x,int y){
    LL res=0;
    while(top[x]!=top[y]){
        if(dfn[top[x]]<dfn[top[y]])swap(x,y);
        res=(res+ask(1,1,n,dfn[top[x]],dfn[x]))%MOD;
        x=Fa[top[x]];
    }if(dfn[x]>dfn[y])swap(x,y);
    res=(res+ask(1,1,n,dfn[x],dfn[y]))%MOD;
    return res;
}
int main(){
    n=read(),Q=read();
    Root=read(),MOD=read();
    for(int i=1;i<=n;i++)a[i]=read();
    for(int i=1;i<n;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }DFS1(Root,0),DFS2(Root,0);
    build(1,1,n);
    while(Q--){
        int opt=read();
        if(opt==1){
            int x=read(),y=read();
            LL k=read();update(x,y,k);
        }else if(opt==2){
            int x=read(),y=read();
            cout<<query(x,y)<<"\n";
        }else if(opt==3){
            int x=read();LL k=read();
            change(1,1,n,dfn[x],dfn[x]+sz[x]-1,k);
        }else{
            int x=read();
            cout<<ask(1,1,n,dfn[x],dfn[x]+sz[x]-1)<<"\n";
        }
    }
    return 0;
}
